html:
{% set thread = get_letter_thread(doc.name) %}
{% set toj = toshamshi if toshamshi is defined else (jalali.toshamshi if jalali is defined else None) %}
<div class="oa-print" dir="auto">
	<style>
		.oa-print { font-family: "Vazirmatn", "B Nazanin", "IRANSans", sans-serif; color: #1a1a1a; }
		.oa-letter-head { display: flex; justify-content: space-between; border-bottom: 2px solid #333; padding-bottom: 8px; margin-bottom: 12px; }
		.oa-letter-head .meta { font-size: 12px; line-height: 1.8; }
		.oa-subject { font-size: 18px; font-weight: 700; margin: 8px 0 4px; }
		.oa-body { font-size: 13px; line-height: 1.9; margin: 12px 0 18px; }
		.oa-attachments { font-size: 12px; margin: 8px 0 18px; }
		.oa-thread-title { font-size: 14px; font-weight: 700; border-top: 1px dashed #999; padding-top: 10px; margin-top: 16px; }
		.oa-referral { border-{{ "right" }}: 3px solid #2490ef; background: #f7fbff; padding: 8px 12px; margin: 8px 0; border-radius: 4px; }
		.oa-referral .route { font-weight: 600; font-size: 12px; }
		.oa-referral .note { font-size: 12px; white-space: pre-wrap; margin-top: 4px; }
		.oa-referral .stamp { font-size: 11px; color: #666; margin-top: 4px; }
		.oa-pill { display: inline-block; font-size: 10px; padding: 1px 8px; border-radius: 10px; background: #e7f0ff; color: #1b62c9; }
	</style>

	{# ---------- Main letter ---------- #}
	<div class="oa-letter-head">
		<div class="meta">
			<div><strong>{{ _("Letter No") }}:</strong> {{ thread.letter.letter_no or doc.name }}</div>
			<div><strong>{{ _("Date") }}:</strong> {{ toj(thread.letter.date, persian_digits=True) if toj else frappe.utils.formatdate(thread.letter.date) }}</div>
		</div>
		<div class="meta" style="text-align:end">
			<div><strong>{{ _("Sender") }}:</strong> {{ frappe.utils.get_fullname(thread.letter.sender) }}</div>
			{% if thread.letter.letter_type %}<div><strong>{{ _("Type") }}:</strong> {{ thread.letter.letter_type }}</div>{% endif %}
			<div><span class="oa-pill">{{ _(thread.letter.status) }}</span></div>
		</div>
	</div>

	<div class="oa-subject">{{ thread.letter.subject }}</div>
	<div class="oa-body">{{ thread.letter.body or "" }}</div>

	{% if thread.letter.attachments %}
	<div class="oa-attachments">
		<strong>{{ _("Attachments") }}:</strong>
		<ul>
			{% for a in thread.letter.attachments %}
			<li>{{ a.title or a.attachment }}{% if a.is_archived %} ({{ _("Archived") }}){% endif %}</li>
			{% endfor %}
		</ul>
	</div>
	{% endif %}

	{# ---------- Referral thread / margin notes (هامش‌نویسی) ---------- #}
	{% if thread.referrals %}
	<div class="oa-thread-title">{{ _("Referrals & Endorsements") }} (هامش‌نویسی)</div>
	{% for r in thread.referrals %}
	<div class="oa-referral" style="margin-{{ 'right' }}: {{ r.depth * 18 }}px">
		<div class="route">
			{{ frappe.utils.get_fullname(r.sender) }} &larr;&rarr; {{ frappe.utils.get_fullname(r.recipient) }}
			{% if r.action_type %}<span class="oa-pill">{{ r.action_type }}</span>{% endif %}
			<span class="oa-pill">{{ _(r.status) }}</span>
		</div>
		{% if r.instruction %}<div class="note">{{ r.instruction }}</div>{% endif %}
		<div class="stamp">
			{{ toj(r.creation, include_time=True, persian_digits=True) if toj else frappe.utils.format_datetime(r.creation) }}
			{% if r.actioned_on %}· {{ _("Actioned") }}: {{ toj(r.actioned_on, include_time=True, persian_digits=True) if toj else frappe.utils.format_datetime(r.actioned_on) }}{% endif %}
		</div>
	</div>
	{% endfor %}
	{% else %}
	<div class="oa-thread-title">{{ _("No referrals recorded.") }}</div>
	{% endif %}
</div>
